You are reight of course, I suppose this is a slightly better solution, still a hack though:

```python
lass MultiProcessCollector(prometheus_client.ProcessCollector):

   def __init__(self, namespace, labels, proc='/proc',
                registry=prometheus_client.REGISTRY):
       self.pids = dict()
       self.labels = labels
       prometheus_client.ProcessCollector.__init__(
           self, namespace, proc=proc, registry=registry)

   def add_pid(self, pid, labels):
       self.pids[pid] = labels

   def remove_pid(self, pid):
       del self.pids[pid]

   def collect(self):
       assert self.pids, 'No processes to collect'

       aggregated_results = dict()
       for pid, labels in self.pids.items():
           self._pid = lambda: pid

           for result in prometheus_client.ProcessCollector.collect(self):
               if result.name not in aggregated_results:
                   aggregated_results[result.name] = result
                   result._labelnames = tuple(self.labels)

               aggregated_result = aggregated_results[result.name]
               aggregated_result.samples += [
                   (name, labels, value)
                   for (name, _, value) in result.samples]

       return aggregated_results.values()

   def describe(self):
       # Using our own process for describing
       self._pid = lambda: 'self'
       return prometheus_client.ProcessCollector.collect(self)
```

